public String populate(List<ConfirmedEventWrapper> events, String parameter) {
    if (parameter == null) {
        throw new IllegalArgumentException(MessageFormatUtil.format(
                CommonsExceptionMessageConstant.INVALID_USAGE_FORMAT_REQUIRED, "usedProducts"));
    }

    final Set<ProductRepresentation> usedProducts = new LinkedHashSet<>();
    for (ConfirmedEventWrapper event : events) {
        usedProducts.add(new ProductRepresentation(event));
    }

    final Set<String> usedProductsRepresentations = new LinkedHashSet<>();
    for (ProductRepresentation representation : usedProducts) {
        usedProductsRepresentations.add(formatProduct(representation, parameter));
    }
    final StringBuilder result = new StringBuilder();
    for (String stringRepresentation : usedProductsRepresentations) {
        if (result.length() > 0) {
            result.append(PRODUCTS_SEPARATOR);
        }

        result.append(stringRepresentation);
    }

    return result.toString();
}

private static String populatePlaceholders(String producerLine, List<ConfirmedEventWrapper> events) {
    int lastIndex = 0;
    Matcher matcher = PATTERN.matcher(producerLine);

    final StringBuilder builder = new StringBuilder();
    while (matcher.find()) {
        builder.append(producerLine.substring(lastIndex, matcher.start()));
        lastIndex = matcher.end();

        final String placeholder = matcher.group(1);
        final int delimiterPosition = placeholder.indexOf(FORMAT_DELIMITER);
        String placeholderName;
        String parameter = null;
        if (placeholder.indexOf(FORMAT_DELIMITER) == -1) {
            placeholderName = placeholder;
        } else {
            placeholderName = placeholder.substring(0, delimiterPosition);
            parameter = placeholder.substring(delimiterPosition + 1);
        }

        final IPlaceholderPopulator populator = PLACEHOLDER_POPULATORS.get(placeholderName);
        if (populator == null) {
            LOGGER.info(MessageFormatUtil.format(
                    CommonsLogMessageConstant.UNKNOWN_PLACEHOLDER_WAS_IGNORED, placeholderName));
        } else {
            builder.append(populator.populate(events, parameter));
        }
    }
    builder.append(producerLine.substring(lastIndex));
    return builder.toString();
}

