        // Use ConfirmedEventWrapper directly to avoid dependency on processor registration.
        List<ConfirmedEventWrapper> events = new ArrayList<>();
        ProductData productData = new ProductData("TestProduct", "TestModule", "1.0", 2000, 2100);
