        Assert.assertTrue(result.contains("middle"));
        Assert.assertTrue(result.contains("end"));
        // Additionally, verify that the result is not just the parameter string.
        Assert.assertNotEquals(parameter, result);
        // Check that the length is reasonable (longer than just the quoted text).
        Assert.assertTrue(result.length() > ("start" + "middle" + "end").length());
    }

