public class AggregatedExceptionTest {

    @Test
    public void aggregatedMessageWithGeneralMessageTest() {
        List<RuntimeException> exceptions = new ArrayList<>();
        exceptions.add(new RuntimeException("Message 1"));
        exceptions.add(new RuntimeException("Message 2"));
        exceptions.add(new CustomException("Message 3"));

        AggregatedException exception = new AggregatedException("General message", exceptions);
        Assert.assertEquals("General message:\n"
                + "0) Message 1\n"
                + "1) Message 2\n"
                + "2) Message 3\n", exception.getMessage());

        List<Exception> returnedExceptions = exception.getAggregatedExceptions();
        Assert.assertEquals(exceptions.size(), returnedExceptions.size());
        for (int i = 0; i < exceptions.size(); i++) {
            Assert.assertEquals(exceptions.get(i).getMessage(), returnedExceptions.get(i).getMessage());
            Assert.assertEquals(exceptions.get(i).getClass(), returnedExceptions.get(i).getClass());
        }
