import java.nio.file.Files;
import java.util.zip.ZipEntry;
import java.util.zip.ZipInputStream;
import org.junit.Assert;
import org.junit.BeforeClass;
import org.junit.Test;
import org.junit.experimental.categories.Category;

@Category(IntegrationTest.class)
public class ZipFileWriterTest extends ExtendedITextTest {

    private static final String SOURCE_FOLDER = "./src/test/resources/com/itextpdf/commons/utils/ZipFileWriter/";
    private static final String DESTINATION_FOLDER = "./target/test/com/itextpdf/commons/utils/ZipFileWriter/";

    @BeforeClass
    public static void beforeClass() {
        createDestinationFolder(DESTINATION_FOLDER);
    }

    @Test
    public void addTextFileEntryTest() throws IOException {
        String zipFilePath = DESTINATION_FOLDER + "addTextFileEntry.zip";
        String sourceFilePath = SOURCE_FOLDER + "testFile.txt";
        String entryName = "text.txt";

        File sourceFile = new File(sourceFilePath);
        Assert.assertTrue("Source file should exist", sourceFile.exists());

        try (ZipFileWriter writer = new ZipFileWriter(zipFilePath)) {
            writer.addEntry(entryName, sourceFile);
        }

        File zipFile = new File(zipFilePath);
        Assert.assertTrue("Zip file should be created", zipFile.exists());

        int entryCount = 0;
        String extractedContent = null;
        try (InputStream fis = Files.newInputStream(zipFile.toPath());
             ZipInputStream zis = new ZipInputStream(fis)) {
            ZipEntry entry;
            while ((entry = zis.getNextEntry()) != null) {
                if (entryName.equals(entry.getName())) {
                    entryCount++;
                    ByteArrayOutputStream baos = new ByteArrayOutputStream();
                    byte[] buffer = new byte[1024];
                    int len;
                    while ((len = zis.read(buffer)) > 0) {
                        baos.write(buffer, 0, len);
                    }
                    extractedContent = baos.toString(StandardCharsets.UTF_8.name());
                }
            }
        }

        String originalContent = new String(Files.readAllBytes(sourceFile.toPath()), StandardCharsets.UTF_8);
        Assert.assertEquals("Zip file should contain exactly one entry", 1, entryCount);
        Assert.assertEquals("Entry content should match original file content", originalContent, extractedContent);
    }
}

