import com.itextpdf.test.ExtendedITextTest;
import com.itextpdf.test.annotations.type.IntegrationTest;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;
import java.util.Arrays;
import java.util.Set;
import org.junit.Assert;
import org.junit.BeforeClass;
import org.junit.Test;
import org.junit.experimental.categories.Category;

@Category(IntegrationTest.class)
public class ZipFileWriterTest extends ExtendedITextTest {

    private static final String SOURCE_FOLDER = "./src/test/resources/com/itextpdf/commons/utils/ZipFileWriter/";
    private static final String DESTINATION_FOLDER = "./target/test/com/itextpdf/commons/utils/ZipFileWriter/";

    @BeforeClass
    public static void beforeClass() {
        createOrClearDestinationFolder(DESTINATION_FOLDER);
    }

    @Test
    public void addJsonEntryTest() throws IOException {
        final String pathToFile = DESTINATION_FOLDER + "addJsonEntry.zip";
        final String fileNameInZip = "entry.json";
        final String jsonContent = "©";

        // Ensure the parent directory exists before creating the ZipFileWriter
        File zipFile = new File(pathToFile);
        File parentDir = zipFile.getParentFile();
        if (parentDir != null && !parentDir.exists()) {
            parentDir.mkdirs();
        }

        // Check if the file already exists, as per the constructor's validation logic
        if (zipFile.exists()) {
            throw new IOException(
                    java.text.MessageFormat.format(CommonsExceptionMessageConstant.FILE_NAME_ALREADY_EXIST, pathToFile));
        }

        try (ZipFileWriter writer = new ZipFileWriter(pathToFile)) {
            writer.addJsonEntry(fileNameInZip, jsonContent);
        }

        Assert.assertTrue("Zip file should be created", zipFile.exists());

        java.util.zip.ZipFile zip = new java.util.zip.ZipFile(zipFile);
        java.util.Enumeration<? extends java.util.zip.ZipEntry> entries = zip.entries();
        int entryCount = 0;
        String entryName = null;
        String extractedContent = null;
        while (entries.hasMoreElements()) {
            java.util.zip.ZipEntry entry = entries.nextElement();
            entryCount++;
            entryName = entry.getName();
            try (InputStream is = zip.getInputStream(entry)) {
                byte[] bytes = new byte[1024];
                int bytesRead;
                ByteArrayOutputStream baos = new ByteArrayOutputStream();
                while ((bytesRead = is.read(bytes)) != -1) {
                    baos.write(bytes, 0, bytesRead);
                }
                extractedContent = baos.toString(StandardCharsets.UTF_8.name());
            }
        }
        zip.close();

        Assert.assertEquals("Zip file should contain exactly one entry", 1, entryCount);
        Assert.assertEquals("Entry name should be 'entry.json'", fileNameInZip, entryName);
        Assert.assertEquals("JSON content should match", jsonContent, extractedContent);
    }

    private static void createOrClearDestinationFolder(String destinationFolder) {
        File destFolder = new File(destinationFolder);
        if (!destFolder.exists()) {
            destFolder.mkdirs();
        } else {
            File[] files = destFolder.listFiles();
            if (files != null) {
                for (File file : files) {
                    file.delete();
                }
            }
        }
    }

}

