            writer.addEntry("entry2.txt", textFile2);
            writer.addJsonEntry("data.json", jsonContent);
        }

        File zipFile = new File(zipPath);
        Assert.assertTrue("Zip file should exist", zipFile.exists());

        Set<String> entryNames = extractZipEntryNames(zipFile);
        Assert.assertEquals("Zip should contain exactly 3 entries", 3, entryNames.size());
        Assert.assertTrue("Zip should contain entry1.txt", entryNames.contains("entry1.txt"));
        Assert.assertTrue("Zip should contain entry2.txt", entryNames.contains("entry2.txt"));
        Assert.assertTrue("Zip should contain data.json", entryNames.contains("data.json"));

        String extractedJson = extractEntryContentAsString(zipFile, "data.json");
        Assert.assertEquals("JSON entry content should match", jsonContent, extractedJson);

        byte[] originalFile1Content = Files.readAllBytes(textFile1.toPath());
        byte[] extractedFile1Content = extractEntryContent(zipFile, "entry1.txt");
        Assert.assertArrayEquals("entry1.txt content should match", originalFile1Content, extractedFile1Content);

        byte[] originalFile2Content = Files.readAllBytes(textFile2.toPath());
        byte[] extractedFile2Content = extractEntryContent(zipFile, "entry2.txt");
        Assert.assertArrayEquals("entry2.txt content should match", originalFile2Content, extractedFile2Content);
    }

    private static void createDestinationFolder(String path) {
        new File(path).mkdirs();
    }

    private static Set<String> extractZipEntryNames(File zipFile) throws IOException {
        java.util.zip.ZipFile zf = new java.util.zip.ZipFile(zipFile);
        Set<String> entryNames = zf.stream().map(java.util.zip.ZipEntry::getName).collect(Collectors.toSet());
        zf.close();
        return entryNames;
    }

    private static byte[] extractEntryContent(File zipFile, String entryName) throws IOException {
        java.util.zip.ZipFile zf = new java.util.zip.ZipFile(zipFile);
        java.util.zip.ZipEntry entry = zf.getEntry(entryName);
        InputStream is = zf.getInputStream(entry);
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        byte[] buffer = new byte[1024];
        int len;
        while ((len = is.read(buffer)) > -1) {
            baos.write(buffer, 0, len);
        }
        baos.flush();
        byte[] content = baos.toByteArray();
        is.close();
        zf.close();
        return content;
    }

    private static String extractEntryContentAsString(File zipFile, String entryName) throws IOException {
        byte[] content = extractEntryContent(zipFile, entryName);
        return new String(content, StandardCharsets.UTF_8);
    }
}

